// AshHero3D.js — Three.js background for the AgentsShowcase hero.
// A glowing wireframe "JARVIS" head with a pulsing neural core, eyes,
// orbit rings, particle aura and starfield (cyan/purple/pink, additive).
// Self-contained; pauses off-screen; skipped entirely on reduced motion.
import React, { useEffect, useRef } from "react";
import * as THREE from "three";

const reduced = () =>
  typeof window !== "undefined" &&
  window.matchMedia &&
  window.matchMedia("(prefers-reduced-motion: reduce)").matches;

function makeGlowTexture() {
  const c = document.createElement("canvas");
  c.width = c.height = 128;
  const g = c.getContext("2d");
  const grad = g.createRadialGradient(64, 64, 0, 64, 64, 64);
  grad.addColorStop(0, "rgba(255,255,255,1)");
  grad.addColorStop(0.25, "rgba(160,220,255,0.6)");
  grad.addColorStop(1, "rgba(0,0,0,0)");
  g.fillStyle = grad;
  g.fillRect(0, 0, 128, 128);
  const tex = new THREE.CanvasTexture(c);
  return tex;
}

const AshHero3D = () => {
  const mountRef = useRef(null);

  useEffect(() => {
    if (reduced()) return;
    const mount = mountRef.current;
    if (!mount) return;

    let W = mount.clientWidth || 1;
    let H = mount.clientHeight || 1;

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2));
    renderer.setSize(W, H);
    mount.appendChild(renderer.domElement);

    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(55, W / H, 0.1, 600);
    camera.position.set(0, 0, 16);

    scene.add(new THREE.AmbientLight(0x223355, 1.1));
    const keyLight = new THREE.PointLight(0x4ad8ff, 2.2, 120);
    keyLight.position.set(6, 8, 10);
    scene.add(keyLight);
    const fillLight = new THREE.PointLight(0x8a6bff, 1.6, 120);
    fillLight.position.set(-8, -4, 8);
    scene.add(fillLight);

    // ---- Starfield ----
    const makeStars = (count, spread, size, color) => {
      const geo = new THREE.BufferGeometry();
      const pos = new Float32Array(count * 3);
      for (let i = 0; i < count; i++) {
        const r = spread * (0.4 + Math.random() * 0.6);
        const th = Math.random() * Math.PI * 2;
        const ph = Math.acos(2 * Math.random() - 1);
        pos[i * 3] = r * Math.sin(ph) * Math.cos(th);
        pos[i * 3 + 1] = r * Math.sin(ph) * Math.sin(th);
        pos[i * 3 + 2] = r * Math.cos(ph) - 30;
      }
      geo.setAttribute("position", new THREE.BufferAttribute(pos, 3));
      const mat = new THREE.PointsMaterial({
        color,
        size,
        transparent: true,
        opacity: 0.8,
        sizeAttenuation: true,
        depthWrite: false,
        blending: THREE.AdditiveBlending,
      });
      return new THREE.Points(geo, mat);
    };
    scene.add(makeStars(700, 220, 0.7, 0x6688cc));
    scene.add(makeStars(220, 140, 1.3, 0x9fcfff));

    // ---- Figure ----
    const figure = new THREE.Group();
    figure.position.y = 1.8;
    figure.scale.setScalar(1.35);
    scene.add(figure);

    const skullGeo = new THREE.IcosahedronGeometry(2.2, 2);
    figure.add(
      new THREE.Mesh(
        skullGeo,
        new THREE.MeshStandardMaterial({
          color: 0x0a1838,
          metalness: 0.6,
          roughness: 0.3,
          transparent: true,
          opacity: 0.5,
          emissive: 0x0a2a5a,
          emissiveIntensity: 0.4,
        })
      )
    );
    figure.add(
      new THREE.Mesh(
        skullGeo,
        new THREE.MeshBasicMaterial({
          color: 0x4ad8ff,
          wireframe: true,
          transparent: true,
          opacity: 0.32,
        })
      )
    );

    // Pulsing neural core
    const coreMat = new THREE.ShaderMaterial({
      transparent: true,
      uniforms: {
        uTime: { value: 0 },
        uColorA: { value: new THREE.Color(0x4ad8ff) },
        uColorB: { value: new THREE.Color(0x8a6bff) },
      },
      vertexShader: `
        varying vec3 vNormal; varying vec3 vPos; uniform float uTime;
        void main() {
          vNormal = normalize(normalMatrix * normal); vPos = position;
          float disp = sin(position.x*4.0 + uTime*2.0)*0.04 + cos(position.y*5.0 + uTime*1.7)*0.04;
          vec3 p = position + normal * disp;
          gl_Position = projectionMatrix * modelViewMatrix * vec4(p, 1.0);
        }`,
      fragmentShader: `
        varying vec3 vNormal; varying vec3 vPos;
        uniform float uTime; uniform vec3 uColorA; uniform vec3 uColorB;
        void main() {
          float fres = pow(1.0 - max(dot(vNormal, vec3(0.0,0.0,1.0)), 0.0), 1.6);
          float n = 0.5 + 0.5 * sin(uTime*3.0 + vPos.y*4.0 + vPos.x*3.0);
          vec3 col = mix(uColorA, uColorB, n) + fres * uColorA * 1.4;
          gl_FragColor = vec4(col, 0.9);
        }`,
      blending: THREE.AdditiveBlending,
      depthWrite: false,
    });
    const core = new THREE.Mesh(new THREE.IcosahedronGeometry(0.95, 3), coreMat);
    figure.add(core);

    const glowTex = makeGlowTexture();
    const coreGlow = new THREE.Sprite(
      new THREE.SpriteMaterial({
        map: glowTex,
        color: 0x4ad8ff,
        transparent: true,
        opacity: 0.85,
        blending: THREE.AdditiveBlending,
        depthWrite: false,
      })
    );
    coreGlow.scale.set(4.5, 4.5, 1);
    figure.add(coreGlow);

    // Eyes
    const eyes = [];
    [-0.65, 0.65].forEach((x) => {
      const eye = new THREE.Mesh(
        new THREE.SphereGeometry(0.22, 16, 16),
        new THREE.MeshBasicMaterial({
          color: 0xbfe9ff,
          transparent: true,
          opacity: 0.95,
        })
      );
      eye.position.set(x, 0.35, 1.95);
      const halo = new THREE.Sprite(
        new THREE.SpriteMaterial({
          map: glowTex,
          color: 0x4ad8ff,
          transparent: true,
          opacity: 0.65,
          blending: THREE.AdditiveBlending,
          depthWrite: false,
        })
      );
      halo.scale.set(1.1, 1.1, 1);
      halo.position.copy(eye.position);
      figure.add(eye);
      figure.add(halo);
      eyes.push(eye);
    });

    // Shoulder rings
    const ringGeo = new THREE.TorusGeometry(2.6, 0.07, 12, 80);
    const ring1 = new THREE.Mesh(
      ringGeo,
      new THREE.MeshBasicMaterial({
        color: 0x4ad8ff,
        transparent: true,
        opacity: 0.4,
      })
    );
    ring1.rotation.x = Math.PI / 2;
    ring1.position.y = -3.0;
    figure.add(ring1);
    const ring2 = new THREE.Mesh(
      ringGeo,
      new THREE.MeshBasicMaterial({
        color: 0x8a6bff,
        transparent: true,
        opacity: 0.3,
      })
    );
    ring2.rotation.x = Math.PI / 2;
    ring2.position.y = -3.6;
    ring2.scale.setScalar(1.18);
    figure.add(ring2);

    // Particle aura
    const auraCount = 600;
    const auraGeo = new THREE.BufferGeometry();
    const auraPos = new Float32Array(auraCount * 3);
    const auraSeed = new Float32Array(auraCount);
    for (let i = 0; i < auraCount; i++) {
      const r = 3.0 + Math.random() * 3.5;
      const th = Math.random() * Math.PI * 2;
      const ph = Math.acos(2 * Math.random() - 1);
      auraPos[i * 3] = r * Math.sin(ph) * Math.cos(th);
      auraPos[i * 3 + 1] = r * Math.sin(ph) * Math.sin(th) - 1.0;
      auraPos[i * 3 + 2] = r * Math.cos(ph);
      auraSeed[i] = Math.random();
    }
    auraGeo.setAttribute("position", new THREE.BufferAttribute(auraPos, 3));
    auraGeo.setAttribute("aSeed", new THREE.BufferAttribute(auraSeed, 1));
    const auraMat = new THREE.ShaderMaterial({
      transparent: true,
      uniforms: {
        uTime: { value: 0 },
        uPixelRatio: { value: renderer.getPixelRatio() },
      },
      vertexShader: `
        attribute float aSeed; uniform float uTime; uniform float uPixelRatio;
        varying float vSeed;
        void main() {
          vSeed = aSeed;
          vec3 p = position;
          float ang = uTime * (0.15 + aSeed * 0.25);
          float cs = cos(ang), sn = sin(ang);
          vec3 np = vec3(p.x*cs - p.z*sn, p.y + sin(uTime*0.6 + aSeed*6.28)*0.25, p.x*sn + p.z*cs);
          vec4 mv = modelViewMatrix * vec4(np, 1.0);
          gl_Position = projectionMatrix * mv;
          gl_PointSize = (2.0 + aSeed*3.0) * uPixelRatio * (18.0 / -mv.z);
        }`,
      fragmentShader: `
        varying float vSeed;
        void main() {
          float d = length(gl_PointCoord - vec2(0.5));
          if (d > 0.5) discard;
          float a = smoothstep(0.5, 0.0, d) * (0.5 + vSeed*0.5);
          vec3 col = mix(vec3(0.29,0.85,1.0), vec3(0.54,0.42,1.0), vSeed);
          gl_FragColor = vec4(col, a);
        }`,
      blending: THREE.AdditiveBlending,
      depthWrite: false,
    });
    figure.add(new THREE.Points(auraGeo, auraMat));

    // ---- Interaction & loop ----
    const mouse = { x: 0, y: 0 };
    const onMouse = (e) => {
      mouse.x = (e.clientX / window.innerWidth) * 2 - 1;
      mouse.y = (e.clientY / window.innerHeight) * 2 - 1;
    };
    window.addEventListener("mousemove", onMouse, { passive: true });

    let raf = null;
    let visible = true;
    const clock = new THREE.Clock();

    const loop = () => {
      raf = requestAnimationFrame(loop);
      if (!visible) return;
      const t = clock.getElapsedTime();
      coreMat.uniforms.uTime.value = t;
      auraMat.uniforms.uTime.value = t;

      // Head follows the cursor, with a slow idle sway
      figure.rotation.y +=
        (mouse.x * 0.45 + Math.sin(t * 0.3) * 0.12 - figure.rotation.y) * 0.04;
      figure.rotation.x +=
        (mouse.y * 0.25 + Math.cos(t * 0.4) * 0.05 - figure.rotation.x) * 0.04;
      figure.position.y = 0.6 + Math.sin(t * 0.8) * 0.15;

      const pulse = 1 + Math.sin(t * 2.2) * 0.08;
      core.scale.setScalar(pulse);
      coreGlow.scale.set(4.5 * pulse, 4.5 * pulse, 1);

      // Occasional blink
      const blink = 1 - Math.pow(Math.max(0, Math.sin(t * 1.4)), 64) * 0.85;
      eyes.forEach((e) => (e.scale.y = blink));

      ring1.rotation.z = t * 0.25;
      ring2.rotation.z = -t * 0.18;

      renderer.render(scene, camera);
    };
    loop();

    // Pause when scrolled out of view
    const io = new IntersectionObserver(
      ([entry]) => {
        visible = entry.isIntersecting;
      },
      { threshold: 0 }
    );
    io.observe(mount);

    const onResize = () => {
      W = mount.clientWidth || 1;
      H = mount.clientHeight || 1;
      camera.aspect = W / H;
      camera.updateProjectionMatrix();
      renderer.setSize(W, H);
    };
    window.addEventListener("resize", onResize);

    return () => {
      cancelAnimationFrame(raf);
      io.disconnect();
      window.removeEventListener("mousemove", onMouse);
      window.removeEventListener("resize", onResize);
      scene.traverse((obj) => {
        if (obj.geometry) obj.geometry.dispose();
        if (obj.material) {
          (Array.isArray(obj.material) ? obj.material : [obj.material]).forEach(
            (m) => {
              if (m.map) m.map.dispose();
              m.dispose();
            }
          );
        }
      });
      glowTex.dispose();
      renderer.dispose();
      if (renderer.domElement.parentNode === mount) {
        mount.removeChild(renderer.domElement);
      }
    };
  }, []);

  return <div className="ash-hero3d" ref={mountRef} aria-hidden="true" />;
};

export default AshHero3D;
