// ============================================
// COUNT-UP NUMBER (animates when in view)
// ============================================
function CountUp({ value, suffix = "" }) {
  const ref = useRef(null);
  const [display, setDisplay] = useState(prefersReducedMotion() ? value : 0);

  useEffect(() => {
    if (prefersReducedMotion()) {
      setDisplay(value);
      return;
    }
    const el = ref.current;
    if (!el) return;
    let raf = null;
    const io = new IntersectionObserver(
      ([entry]) => {
        if (!entry.isIntersecting) return;
        io.disconnect();
        const start = performance.now();
        const dur = 1200;
        const tick = (now) => {
          const t = Math.min((now - start) / dur, 1);
          const eased = 1 - Math.pow(1 - t, 3);
          setDisplay(Math.round(eased * value));
          if (t < 1) raf = requestAnimationFrame(tick);
        };
        raf = requestAnimationFrame(tick);
      },
      { threshold: 0.5 }
    );
    io.observe(el);
    return () => {
      io.disconnect();
      if (raf) cancelAnimationFrame(raf);
    };
  }, [value]);

  return (
    <span ref={ref}>
      {display}
      {suffix}
    </span>
  );
}

// ============================================
// LIVE TERMINAL — auto-types agent runs
// ============================================
function AgentTerminal() {
  const [lines, setLines] = useState([]);
  const [current, setCurrent] = useState("");
  const stateRef = useRef({ script: 0, line: 0, char: 0 });
  const timerRef = useRef(null);

  useEffect(() => {
    if (prefersReducedMotion()) {
      setLines(TERMINAL_SCRIPTS[0]);
      return;
    }
    const step = () => {
      const s = stateRef.current;
      const script = TERMINAL_SCRIPTS[s.script];
      const line = script[s.line];

      if (!line) {
        // Script finished — hold, then wipe and move to the next one
        timerRef.current = setTimeout(() => {
          stateRef.current = {
            script: (s.script + 1) % TERMINAL_SCRIPTS.length,
            line: 0,
            char: 0,
          };
          setLines([]);
          setCurrent("");
          step();
        }, 2600);
        return;
      }

      if (s.char < line.t.length) {
        const isCmd = line.cls === "cmd";
        s.char += isCmd ? 1 : 3; // commands "type", output "prints"
        setCurrent(line.t.slice(0, s.char));
        timerRef.current = setTimeout(step, isCmd ? 34 : 12);
      } else {
        setLines((prev) => [...prev, line]);
        setCurrent("");
        s.line += 1;
        s.char = 0;
        timerRef.current = setTimeout(step, line.cls === "cmd" ? 420 : 210);
      }
    };
    timerRef.current = setTimeout(step, 900);
    return () => clearTimeout(timerRef.current);
  }, []);

  const currentCls =
    TERMINAL_SCRIPTS[stateRef.current.script]?.[stateRef.current.line]?.cls ||
    "cmd";

  return (
    <div className="ash-terminal" aria-hidden="true">
      <div className="ash-terminal-bar">
        <span className="ash-tdot ash-tdot-r" />
        <span className="ash-tdot ash-tdot-y" />
        <span className="ash-tdot ash-tdot-g" />
        <span className="ash-terminal-title">laxman@ai-experience-center</span>
        <span className="ash-terminal-live">● live</span>
      </div>
      <div className="ash-terminal-body">
        {lines.map((l, i) => (
          <div key={i} className={`ash-tline ash-tline-${l.cls}`}>
            {l.t}
          </div>
        ))}
        <div className={`ash-tline ash-tline-${currentCls}`}>
          {current}
          <span className="ash-tcursor">▋</span>
        </div>
      </div>
    </div>
  );
}

// ============================================
// AGENT ORCHESTRA — interactive SVG network
// ============================================
function AgentOrchestra() {
  const [active, setActive] = useState(0);
  const [hovered, setHovered] = useState(null);
  const idx = hovered !== null ? hovered : active;

  // Auto-cycle the active agent unless the user is hovering one
  useEffect(() => {
    if (prefersReducedMotion() || hovered !== null) return;
    const id = setInterval(
      () => setActive((a) => (a + 1) % AGENTS.length),
      2400
    );
    return () => clearInterval(id);
  }, [hovered]);

  const W = 760;
  const H = 420;
  const CX = W / 2;
  const CY = H / 2;
  const positions = useMemo(
    () =>
      AGENTS.map((_, i) => {
        const angle = (i / AGENTS.length) * Math.PI * 2 - Math.PI / 2;
        return {
          x: CX + Math.cos(angle) * 250,
          y: CY + Math.sin(angle) * 138,
        };
      }),
    [CX, CY]
  );

  return (
    <div className="ash-orchestra">
      <svg
        viewBox={`0 0 ${W} ${H}`}
        className="ash-orchestra-svg"
        role="img"
        aria-label="Six AI agents connected to one task"
      >
        {/* Edges */}
        {positions.map((p, i) => (
          <line
            key={`e-${i}`}
            x1={CX}
            y1={CY}
            x2={p.x}
            y2={p.y}
            className={`ash-edge ${i === idx ? "ash-edge-active" : ""}`}
          />
        ))}

        {/* Center task node */}
        <g className="ash-center-node">
          <circle cx={CX} cy={CY} r="46" className="ash-center-ring" />
          <circle cx={CX} cy={CY} r="38" className="ash-center-core" />
          <text
            x={CX}
            y={CY - 4}
            textAnchor="middle"
            className="ash-center-emoji"
          >
            ⚡
          </text>
          <text
            x={CX}
            y={CY + 16}
            textAnchor="middle"
            className="ash-center-label"
          >
            your task
          </text>
        </g>

        {/* Agent nodes */}
        {AGENTS.map((agent, i) => {
          const p = positions[i];
          const isOn = i === idx;
          return (
            <g
              key={agent.name}
              className={`ash-agent-node ${isOn ? "ash-agent-active" : ""}`}
              onMouseEnter={() => setHovered(i)}
              onMouseLeave={() => setHovered(null)}
              onClick={() => setActive(i)}
              style={{ cursor: "pointer" }}
            >
              <circle cx={p.x} cy={p.y} r="30" className="ash-agent-halo" />
              <circle cx={p.x} cy={p.y} r="24" className="ash-agent-core" />
              <text
                x={p.x}
                y={p.y + 6}
                textAnchor="middle"
                className="ash-agent-emoji"
              >
                {agent.icon}
              </text>
              <text
                x={p.x}
                y={p.y + (p.y > CY ? 48 : -38)}
                textAnchor="middle"
                className="ash-agent-label"
              >
                {agent.name}
              </text>
            </g>
          );
        })}
      </svg>

      <div className="ash-orchestra-caption" aria-live="polite">
        <span className="ash-orchestra-icon">{AGENTS[idx].icon}</span>
        <div>
          <strong>{AGENTS[idx].name}</strong>
          <p>{AGENTS[idx].blurb}</p>
        </div>
      </div>
    </div>
  );
}

// ============================================
// TILT CARD — 3D hover tilt (fine pointers)
// ============================================
function TiltCard({ children, className, style, ...rest }) {
  const ref = useRef(null);
  const rafRef = useRef(null);

  const onMove = useCallback((e) => {
    if (!isFinePointer() || prefersReducedMotion()) return;
    if (rafRef.current) cancelAnimationFrame(rafRef.current);
    rafRef.current = requestAnimationFrame(() => {
      const el = ref.current;
      if (!el) return;
      const r = el.getBoundingClientRect();
      const x = e.clientX - r.left;
      const y = e.clientY - r.top;
      const rx = ((r.height / 2 - y) / r.height) * 8;
      const ry = ((x - r.width / 2) / r.width) * 8;
      el.style.transform = `perspective(800px) rotateX(${rx}deg) rotateY(${ry}deg) translateY(-6px)`;
      el.style.setProperty("--mx", `${x}px`);
      el.style.setProperty("--my", `${y}px`);
    });
  }, []);

  const onLeave = useCallback(() => {
    if (rafRef.current) cancelAnimationFrame(rafRef.current);
    if (ref.current) ref.current.style.transform = "";
  }, []);

  return (
    <article
      ref={ref}
      className={className}
      style={style}
      onMouseMove={onMove}
      onMouseLeave={onLeave}
      {...rest}
    >
      {children}
    </article>
  );
}

