  const handleTry = useCallback((tool) => {
    setNudgeTool(tool.name);
    signinRef.current?.scrollIntoView({ behavior: "smooth", block: "center" });
    clearTimeout(nudgeTimer.current);
    nudgeTimer.current = setTimeout(() => setNudgeTool(null), 6000);
  }, []);

  useEffect(() => () => clearTimeout(nudgeTimer.current), []);

  // ---- One rAF-throttled scroll listener: progress bar, hero parallax,
  // ---- orb drift, and per-element parallax via [data-ash-speed] ----
  useEffect(() => {
    if (prefersReducedMotion()) return;
    let raf = null;
    const parallaxEls = rootRef.current
      ? Array.from(rootRef.current.querySelectorAll("[data-ash-speed]"))
      : [];
    const update = () => {
      raf = null;
      const y = window.scrollY;
      const doc = document.documentElement;
      const max = doc.scrollHeight - window.innerHeight || 1;
      if (progressRef.current) {
        progressRef.current.style.transform = `scaleX(${Math.min(y / max, 1)})`;
      }
      if (heroInnerRef.current) {
        const fade = Math.min(y / 560, 1);
        heroInnerRef.current.style.transform = `translateY(${y * 0.22}px)`;
        heroInnerRef.current.style.opacity = `${1 - fade * 0.8}`;
      }
      parallaxEls.forEach((el) => {
        const speed = parseFloat(el.dataset.ashSpeed) || 0;
        const rect = el.getBoundingClientRect();
        const mid = rect.top + rect.height / 2 - window.innerHeight / 2;
        el.style.transform = `translate3d(0, ${mid * speed * -0.1}px, 0)`;
      });
    };
    const onScroll = () => {
      if (!raf) raf = requestAnimationFrame(update);
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    window.addEventListener("resize", onScroll);
    update();
    return () => {
      window.removeEventListener("scroll", onScroll);
      window.removeEventListener("resize", onScroll);
      if (raf) cancelAnimationFrame(raf);
    };
  }, []);

  // ---- Cursor spotlight in the hero (fine pointers only) ----
  useEffect(() => {
    if (prefersReducedMotion() || !isFinePointer()) return;
    const hero = heroRef.current;
    const spot = spotRef.current;
    if (!hero || !spot) return;
    let raf = null;
    const onMove = (e) => {
      const rect = hero.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      if (!raf) {
        raf = requestAnimationFrame(() => {
          raf = null;
          spot.style.transform = `translate(${x}px, ${y}px) translate(-50%, -50%)`;
          spot.style.opacity = "1";
        });
      }
    };
    const onLeave = () => {
      spot.style.opacity = "0";
    };
    hero.addEventListener("mousemove", onMove);
    hero.addEventListener("mouseleave", onLeave);
    return () => {
      hero.removeEventListener("mousemove", onMove);
      hero.removeEventListener("mouseleave", onLeave);
      if (raf) cancelAnimationFrame(raf);
    };
  }, []);

  // ---- Reveal-on-scroll ----
  useEffect(() => {
    const els = rootRef.current
      ? rootRef.current.querySelectorAll("[data-ash-reveal]")
      : [];
    if (prefersReducedMotion()) {
      els.forEach((el) => el.classList.add("ash-revealed"));
      return;
    }
    const io = new IntersectionObserver(
      (entries) => {
        entries.forEach((e) => {
          if (e.isIntersecting) {
            e.target.classList.add("ash-revealed");
            io.unobserve(e.target);
          }
        });
      },
      { threshold: 0.08, rootMargin: "0px 0px -30px 0px" }
    );
    els.forEach((el) => io.observe(el));
    return () => io.disconnect();
  }, []);

  const signinBlock = !isPreview ? (
    <div className="ash-signin-btn">
      <LoginButton theme={theme} />
    </div>
  ) : (
    <a className="ash-enter-btn" href="/myspace">
      Enter your workspace →
    </a>
  );

