// VoiceInterview.js — Live voice-driven AI mock interview (self-contained)
//
// The interviewer SPEAKS every question (speechSynthesis) and LISTENS to the
// candidate's answer (SpeechRecognition), with seamless turn-taking:
//
//   speaking ──(TTS ends + echo guard)──▶ listening ──(silence / "done")──▶
//   thinking ──(Gemini JSON turn)──▶ speaking … ──▶ feedback report
//
// Voice engine patterns (utterance chunking for iOS, cancel tokens, platform
// aware continuous mode, bounded retries) are adapted from Siri.js.
// Falls back to text mode when SpeechRecognition is unavailable (Firefox) or
// the mic is muted/denied — TTS still speaks if available.

import React, {
  useState,
  useEffect,
  useCallback,
  useRef,
  useMemo,
} from "react";
import "./VoiceInterview.css";

// ===== Environment detection =====
const SpeechRecognitionCtor =
  typeof window !== "undefined"
    ? window.SpeechRecognition || window.webkitSpeechRecognition
    : null;
const TTS_SUPPORTED =
  typeof window !== "undefined" && "speechSynthesis" in window;
const IS_IOS =
  typeof navigator !== "undefined" &&
  (/iPad|iPhone|iPod/.test(navigator.userAgent) ||
    (navigator.platform === "MacIntel" && navigator.maxTouchPoints > 1));
const IS_MOBILE =
  typeof navigator !== "undefined" && /Mobi|Android/i.test(navigator.userAgent);

// Interview answers are long-form: give the candidate breathing room before
// treating silence as end-of-answer (Siri.js uses 700-1000ms for commands).
const EOS_AFTER_FINAL_MS = 2200;
const EOS_STABLE_INTERIM_MS = 2800;
const MAX_LISTEN_MS = IS_MOBILE ? 60000 : 120000;
const ECHO_GUARD_MS = IS_MOBILE ? 1000 : 600;
const MAX_RECOGNITION_RETRIES = 3;
const TTS_CHUNK_LEN = IS_MOBILE ? 160 : 220;

const ROLE_PRESETS = [
  { id: "sde", label: "Software Engineer", icon: "💻" },
  { id: "ml", label: "ML Engineer", icon: "🤖" },
  { id: "fullstack", label: "Full-Stack Developer", icon: "🌐" },
  { id: "ai", label: "AI Engineer", icon: "🧠" },
  { id: "data", label: "Data Scientist", icon: "📊" },
];

const INTERVIEW_TYPES = [
  { id: "technical", label: "Technical", desc: "Concepts, systems, coding" },
  { id: "behavioral", label: "Behavioral", desc: "STAR stories, teamwork" },
  { id: "mixed", label: "Mixed", desc: "Both, like a real loop" },
];

// Extract the first JSON object from an LLM reply (tolerates ``` fences,
// leading prose, trailing text).
function extractJson(raw) {
  if (!raw || typeof raw !== "string") return null;
  const cleaned = raw
    .replace(/```json/gi, "")
    .replace(/```/g, "")
    .trim();
  const start = cleaned.indexOf("{");
  const end = cleaned.lastIndexOf("}");
  if (start === -1 || end <= start) return null;
  try {
    return JSON.parse(cleaned.slice(start, end + 1));
  } catch (e) {
    return null;
  }
}

function formatClock(seconds) {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${String(s).padStart(2, "0")}`;
}

export default function VoiceInterview({ callGeminiAPI, portfolioKnowledge }) {
  // ===== Config (setup screen) =====
  const [role, setRole] = useState("");
  const [interviewType, setInterviewType] = useState("mixed");
  const [numQuestions, setNumQuestions] = useState(5);
  const [voiceEnabled, setVoiceEnabled] = useState(TTS_SUPPORTED);

  // ===== Session state =====
  // phase: setup | starting | speaking | listening | thinking | report_loading | report
  const [phase, setPhase] = useState("setup");
  const [messages, setMessages] = useState([]);
  const [questionNumber, setQuestionNumber] = useState(0);
  const [interim, setInterim] = useState("");
  const [capturedSoFar, setCapturedSoFar] = useState("");
  const [micMuted, setMicMuted] = useState(!SpeechRecognitionCtor);
  const [micDenied, setMicDenied] = useState(false);
  const [textDraft, setTextDraft] = useState("");
  const [banner, setBanner] = useState(null); // {kind: 'info'|'error', text}
  const [elapsed, setElapsed] = useState(0);
  const [report, setReport] = useState(null);

  // ===== Refs (live values for event handler closures) =====
  const phaseRef = useRef(phase);
  const mutedRef = useRef(micMuted);
  const messagesRef = useRef(messages);
  const questionNumberRef = useRef(0);
  const recognitionRef = useRef(null);
  const finalTranscriptRef = useRef("");
  const lastInterimRef = useRef("");
  const silenceTimerRef = useRef(null);
  const maxListenTimerRef = useRef(null);
  const echoGuardTimerRef = useRef(null);
  const speakTokenRef = useRef(null);
  const heartbeatRef = useRef(null);
  const retryCountRef = useRef(0);
  const submittingRef = useRef(false);
  const mountedRef = useRef(true);
  const transcriptEndRef = useRef(null);
  const voiceEnabledRef = useRef(voiceEnabled);

  useEffect(() => {
    phaseRef.current = phase;
  }, [phase]);
  // Turn-taking logic reads phaseRef inside async flows that can resume in
  // the same tick as a phase change (e.g. TTS disabled → speak() resolves
  // immediately) — update the ref synchronously, not just via effect.
  const changePhase = useCallback((p) => {
    phaseRef.current = p;
    setPhase(p);
  }, []);
  useEffect(() => {
    mutedRef.current = micMuted;
  }, [micMuted]);
  useEffect(() => {
    messagesRef.current = messages;
  }, [messages]);
  useEffect(() => {
    voiceEnabledRef.current = voiceEnabled;
  }, [voiceEnabled]);

  const inSession = ["starting", "speaking", "listening", "thinking"].includes(
    phase
  );

  // ===== Elapsed timer =====
  useEffect(() => {
    if (!inSession) return undefined;
    const t = setInterval(() => setElapsed((s) => s + 1), 1000);
    return () => clearInterval(t);
  }, [inSession]);

  // ===== Auto-scroll transcript =====
  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, interim, phase]);

  const showBanner = useCallback((kind, text, ms = 4000) => {
    setBanner({ kind, text });
    if (ms) {
      setTimeout(() => {
        if (mountedRef.current) setBanner(null);
      }, ms);
    }
  }, []);

  // ===== Teardown helpers =====
  const clearTimers = useCallback(() => {
    [silenceTimerRef, maxListenTimerRef, echoGuardTimerRef].forEach((r) => {
      if (r.current) {
        clearTimeout(r.current);
        r.current = null;
      }
    });
    if (heartbeatRef.current) {
      clearInterval(heartbeatRef.current);
      heartbeatRef.current = null;
    }
  }, []);

  const stopRecognition = useCallback(() => {
    if (recognitionRef.current) {
      const rec = recognitionRef.current;
      recognitionRef.current = null;
      try {
        rec.onresult = null;
        rec.onend = null;
        rec.onerror = null;
        rec.stop();
      } catch (e) {
        /* already stopped */
      }
    }
  }, []);

  const stopSpeaking = useCallback(() => {
    speakTokenRef.current = null; // invalidate pending utterance callbacks
    if (TTS_SUPPORTED) {
      try {
        window.speechSynthesis.cancel();
      } catch (e) {
        /* noop */
      }
    }
  }, []);

  const stopAllAudio = useCallback(() => {
    clearTimers();
    stopRecognition();
    stopSpeaking();
  }, [clearTimers, stopRecognition, stopSpeaking]);

  // Full cleanup on unmount / tab switch away
  useEffect(() => {
    mountedRef.current = true;
    return () => {
      mountedRef.current = false;
      clearTimers();
      if (recognitionRef.current) {
        try {
          recognitionRef.current.stop();
        } catch (e) {
          /* noop */
        }
        recognitionRef.current = null;
      }
      speakTokenRef.current = null;
      if (TTS_SUPPORTED) {
        try {
          window.speechSynthesis.cancel();
        } catch (e) {
          /* noop */
        }
      }
    };
  }, [clearTimers]);

  // ===== TTS: speak(text) -> Promise<void> (resolves on finish OR cancel) =====
  const pickVoice = useCallback(() => {
    if (!TTS_SUPPORTED) return null;
    const voices = window.speechSynthesis.getVoices();
    if (!voices.length) return null;
    return (
      voices.find(
        (v) =>
          v.lang.includes("en-US") &&
          (v.name.includes("Google") || v.name.includes("Natural"))
      ) ||
      voices.find((v) => v.lang.includes("en-US")) ||
      voices[0]
    );
  }, []);

  const speak = useCallback(
    (text) =>
      new Promise((resolve) => {
        if (!TTS_SUPPORTED || !voiceEnabledRef.current || !text?.trim()) {
          resolve();
          return;
        }

        window.speechSynthesis.cancel();

        // Chunk on sentence boundaries — dodges the iOS Safari ~200 char
        // utterance truncation bug (same approach as Siri.js).
        const chunkText = (input) => {
          const trimmed = input.trim();
          if (trimmed.length <= TTS_CHUNK_LEN) return [trimmed];
          const parts = trimmed.match(/[^.!?\n]+[.!?]?\s*/g) || [trimmed];
          const out = [];
          let buf = "";
          for (const p of parts) {
            if ((buf + p).length > TTS_CHUNK_LEN && buf) {
              out.push(buf.trim());
              buf = p;
            } else {
              buf += p;
            }
            while (buf.length > TTS_CHUNK_LEN) {
              const cut = buf.lastIndexOf(" ", TTS_CHUNK_LEN);
              const idx = cut > TTS_CHUNK_LEN * 0.5 ? cut : TTS_CHUNK_LEN;
              out.push(buf.slice(0, idx).trim());
              buf = buf.slice(idx).trim();
            }
          }
          if (buf.trim()) out.push(buf.trim());
          return out.filter(Boolean);
        };

        const chunks = chunkText(text);
        const myToken = Symbol("vi-speak");
        speakTokenRef.current = myToken;
        const isCurrent = () => speakTokenRef.current === myToken;
        const finish = () => {
          if (heartbeatRef.current) {
            clearInterval(heartbeatRef.current);
            heartbeatRef.current = null;
          }
          resolve();
        };

        const voice = pickVoice();
        let doneCount = 0;

        chunks.forEach((chunk, i) => {
          const u = new SpeechSynthesisUtterance(chunk);
          u.lang = "en-US";
          u.rate = IS_MOBILE ? 0.95 : 1.0;
          u.pitch = 1.02;
          u.volume = 0.9;
          if (voice) u.voice = voice;

          u.onend = () => {
            if (!isCurrent()) return finish();
            doneCount += 1;
            if (doneCount >= chunks.length) finish();
          };
          u.onerror = (ev) => {
            // canceled/interrupted are expected on barge-in / teardown
            if (!isCurrent()) return finish();
            if (ev.error !== "canceled" && ev.error !== "interrupted") {
              console.warn("🔊 VI speech error:", ev.error);
            }
            finish();
          };
          window.speechSynthesis.speak(u);
          void i;
        });

        // iOS Safari pauses long synthesis after ~15s; pump keeps it alive.
        if (IS_MOBILE) {
          heartbeatRef.current = setInterval(() => {
            if (!isCurrent() || !window.speechSynthesis.speaking) {
              clearInterval(heartbeatRef.current);
              heartbeatRef.current = null;
              return;
            }
            try {
              window.speechSynthesis.pause();
              window.speechSynthesis.resume();
            } catch (e) {
              /* noop */
            }
          }, 10000);
        }

        // Safety: if the synthesis engine silently dies, don't hang the loop.
        const estMs = Math.min(90000, 4000 + text.length * 90);
        setTimeout(() => {
          if (isCurrent() && !window.speechSynthesis.speaking) finish();
        }, estMs);
      }),
    [pickVoice]
  );

  // Preload voices (Chrome loads them async)
  useEffect(() => {
    if (!TTS_SUPPORTED) return undefined;
    const load = () => window.speechSynthesis.getVoices();
    load();
    window.speechSynthesis.addEventListener("voiceschanged", load);
    return () =>
      window.speechSynthesis.removeEventListener("voiceschanged", load);
  }, []);

  // ===== Interview brain (Gemini structured turns) =====
  const buildHistoryText = useCallback((msgs) => {
    return msgs
      .slice(-24)
      .map(
        (m) =>
          `${m.role === "interviewer" ? "Interviewer" : "Candidate"}: ${
            m.content
          }`
      )
      .join("\n\n");
  }, []);

  const candidateContext = useMemo(() => {
    if (!portfolioKnowledge?.profile) return "";
    const p = portfolioKnowledge.profile;
    return `CANDIDATE BACKGROUND (use to personalize questions):
Name: ${p.name || "Candidate"} — ${p.title || ""}
Education: ${p.education || ""}
Expertise: ${(p.expertise || []).join(", ")}
Summary: ${p.profileSummary || ""}`;
  }, [portfolioKnowledge]);

  const buildTurnPrompt = useCallback(
    (msgs, qNum) => {
      const typeLabel =
        INTERVIEW_TYPES.find((t) => t.id === interviewType)?.label ||
        interviewType;
      return `You are "Alex", a warm but rigorous senior interviewer at a top tech company, running a LIVE VOICE mock interview.

ROLE BEING INTERVIEWED FOR: ${role}
INTERVIEW STYLE: ${typeLabel}
PLANNED MAIN QUESTIONS: ${numQuestions}
MAIN QUESTIONS ASKED SO FAR: ${qNum}

${candidateContext}

CONVERSATION SO FAR:
${buildHistoryText(msgs) || "(interview has not started yet)"}

STRICT OUTPUT RULES — your words are read aloud by text-to-speech:
- Plain spoken English only. NO markdown, NO bullet points, NO emojis, NO code, NO stage directions.
- Maximum 70 words.
- If the interview has not started: give a one-sentence friendly intro as Alex, then ask main question 1.
- Otherwise: react to the candidate's last answer in ONE specific sentence (something concrete they said), then either ask ONE short probing follow-up (at most one follow-up per main question) or move to the next main question.
- If the candidate skipped, move on gracefully without judgment.
- If ${qNum} >= ${numQuestions} and the last answer is complete: thank them, say the interview is over and that their feedback report is being prepared, and set done to true.

Respond with ONLY this JSON, nothing else:
{"say": "<what Alex says out loud>", "questionNumber": <main question number now being asked, integer>, "done": <true|false>}`;
    },
    [role, interviewType, numQuestions, candidateContext, buildHistoryText]
  );

  const buildReportPrompt = useCallback(
    (msgs) => {
      return `You are an expert interview coach. Analyze this mock interview transcript for the role "${role}" and produce a candid, specific feedback report.

TRANSCRIPT:
${buildHistoryText(msgs)}

Score fairly: short/vague answers score low, structured specific answers score high.

Respond with ONLY this JSON, nothing else:
{
  "overallScore": <0-100 integer>,
  "verdict": "<one-line hiring-signal summary, max 15 words>",
  "categories": [
    {"name": "Technical depth", "score": <0-10>, "comment": "<max 20 words>"},
    {"name": "Communication", "score": <0-10>, "comment": "<max 20 words>"},
    {"name": "Structure (STAR/clarity)", "score": <0-10>, "comment": "<max 20 words>"},
    {"name": "Role fit", "score": <0-10>, "comment": "<max 20 words>"}
  ],
  "strengths": ["<specific strength>", "<specific strength>", "<specific strength>"],
  "improvements": ["<specific actionable improvement>", "<specific actionable improvement>", "<specific actionable improvement>"],
  "sampleAnswerTip": "<rewrite ONE of their weaker answers in 2-3 sentences showing how it should sound>"
}`;
    },
    [role, buildHistoryText]
  );

  // ===== Turn-taking core =====
  // Forward declaration dance: startListening and runInterviewerTurn call
  // each other, so both live in refs.
  const startListeningRef = useRef(null);
  const runInterviewerTurnRef = useRef(null);

  const speakThenListen = useCallback(
    async (text) => {
      changePhase("speaking");
      await speak(text);
      if (!mountedRef.current) return;
      // Session may have been ended mid-speech
      if (phaseRef.current !== "speaking") return;

      if (mutedRef.current || !SpeechRecognitionCtor) {
        changePhase("listening"); // text-mode "your turn"
        return;
      }
      // Echo guard: let speaker output die down before opening the mic
      echoGuardTimerRef.current = setTimeout(() => {
        echoGuardTimerRef.current = null;
        if (!mountedRef.current || phaseRef.current !== "speaking") return;
        startListeningRef.current?.();
      }, ECHO_GUARD_MS);
      // phase flips to "listening" inside startListening
    },
    [speak, changePhase]
  );

  const submitAnswer = useCallback(
    (answerText, meta = {}) => {
      const text = (answerText || "").trim();
      if (!text || submittingRef.current) return;
      submittingRef.current = true;

      clearTimeout(silenceTimerRef.current);
      silenceTimerRef.current = null;
      clearTimeout(maxListenTimerRef.current);
      maxListenTimerRef.current = null;

      // Detach + stop recognition so late onend/onresult can't double-fire
      if (recognitionRef.current) {
        const rec = recognitionRef.current;
        recognitionRef.current = null;
        try {
          rec.onresult = null;
          rec.onend = null;
          rec.onerror = null;
          rec.stop();
        } catch (e) {
          /* noop */
        }
      }

      setInterim("");
      setCapturedSoFar("");
      finalTranscriptRef.current = "";
      lastInterimRef.current = "";

      const userMessage = {
        role: "candidate",
        content: meta.skipped ? "(skipped this question)" : text,
        timestamp: Date.now(),
      };
      const nextMessages = [...messagesRef.current, userMessage];
      setMessages(nextMessages);
      changePhase("thinking");

      runInterviewerTurnRef.current?.(nextMessages).finally(() => {
        submittingRef.current = false;
      });
    },
    [changePhase]
  );
  const submitAnswerRef = useRef(submitAnswer);
  useEffect(() => {
    submitAnswerRef.current = submitAnswer;
  }, [submitAnswer]);

  const startListening = useCallback(
    (isRestart = false) => {
      if (!SpeechRecognitionCtor || mutedRef.current) {
        changePhase("listening");
        return;
      }
      if (recognitionRef.current) return; // already listening

      const recognition = new SpeechRecognitionCtor();
      recognitionRef.current = recognition;

      // Platform-aware (Siri.js finding): iOS implements continuous loosely and
      // is less buggy with continuous=false + manual restart on onend.
      recognition.continuous = !IS_IOS;
      recognition.interimResults = true;
      recognition.lang = "en-US";
      recognition.maxAlternatives = 1;

      // On an engine auto-restart mid-answer (iOS ends every ~5s of silence),
      // keep the transcript accumulated so far.
      if (!isRestart) {
        finalTranscriptRef.current = "";
        lastInterimRef.current = "";
        setInterim("");
        setCapturedSoFar("");
      }
      changePhase("listening");

      const armMaxListen = () => {
        // Arm ONCE per answer turn — restarts must not extend the ceiling
        if (maxListenTimerRef.current) return;
        maxListenTimerRef.current = setTimeout(() => {
          maxListenTimerRef.current = null;
          if (phaseRef.current !== "listening") return;
          const captured =
            finalTranscriptRef.current.trim() || lastInterimRef.current.trim();
          if (captured.length >= 2) {
            submitAnswerRef.current?.(captured);
          } else {
            showBanner(
              "info",
              "🎙️ I didn't catch anything — you can also type your answer below."
            );
            setMicMuted(true);
            stopRecognition();
          }
        }, MAX_LISTEN_MS);
      };

      recognition.onstart = () => {
        armMaxListen();
      };

      recognition.onresult = (event) => {
        // Real speech arrived — restore the silent-restart budget
        retryCountRef.current = 0;
        let interimText = "";
        let hasFinal = false;
        for (let i = event.resultIndex; i < event.results.length; i++) {
          const t = event.results[i][0].transcript;
          if (event.results[i].isFinal) {
            finalTranscriptRef.current += t.trim() + " ";
            hasFinal = true;
          } else {
            interimText += t;
          }
        }
        if (hasFinal) setCapturedSoFar(finalTranscriptRef.current.trim());
        setInterim(interimText.trim());
        if (interimText.trim()) lastInterimRef.current = interimText.trim();

        // End-of-answer: silence after speech. Longer windows than a command
        // assistant — interview answers contain natural thinking pauses.
        clearTimeout(silenceTimerRef.current);
        const eos = hasFinal ? EOS_AFTER_FINAL_MS : EOS_STABLE_INTERIM_MS;
        silenceTimerRef.current = setTimeout(() => {
          silenceTimerRef.current = null;
          if (phaseRef.current !== "listening") return;
          const answer =
            (finalTranscriptRef.current + " " + (lastInterimRef.current || ""))
              .replace(/\s+/g, " ")
              .trim() || "";
          // Only auto-submit a real answer; keep listening on tiny fragments
          if (
            finalTranscriptRef.current.trim().length >= 2 ||
            lastInterimRef.current.length >= 5
          ) {
            submitAnswerRef.current?.(answer);
          }
        }, eos);
      };

      recognition.onerror = (event) => {
        if (event.error === "aborted") return; // deliberate stop
        if (
          event.error === "not-allowed" ||
          event.error === "service-not-allowed"
        ) {
          setMicDenied(true);
          setMicMuted(true);
          stopRecognition();
          showBanner(
            "error",
            "🎙️ Microphone blocked — switched to typing. Allow mic access and unmute to talk.",
            6000
          );
          return;
        }
        if (event.error === "no-speech") return; // onend will restart
        console.warn("🎙️ VI recognition error:", event.error);
      };

      recognition.onend = () => {
        // Engine ended on its own (iOS ~5s silence, mobile timeouts, no-speech).
        // If we're still mid-answer, restart and keep accumulating.
        if (recognitionRef.current !== recognition) return; // superseded
        recognitionRef.current = null;
        if (phaseRef.current !== "listening" || submittingRef.current) return;

        // Restart and keep accumulating. iOS ends naturally every ~5s so its
        // budget is only consumed by fully-silent restarts (reset on onresult);
        // the max-listen ceiling still bounds the whole answer turn.
        const hasSpeechSoFar =
          finalTranscriptRef.current.trim().length >= 2 ||
          lastInterimRef.current.length >= 2;
        if (retryCountRef.current < MAX_RECOGNITION_RETRIES || hasSpeechSoFar) {
          if (!hasSpeechSoFar) retryCountRef.current += 1;
          try {
            startListeningRef.current?.(true);
          } catch (e) {
            /* noop */
          }
        } else {
          const captured = finalTranscriptRef.current.trim();
          if (captured.length >= 2) {
            submitAnswerRef.current?.(captured);
          } else {
            setMicMuted(true);
            showBanner(
              "info",
              "🎙️ Having trouble hearing you — type your answer below or unmute to retry."
            );
          }
        }
      };

      try {
        recognition.start();
      } catch (e) {
        recognitionRef.current = null;
        console.warn("🎙️ VI recognition start failed:", e?.message);
      }
    },
    [showBanner, stopRecognition, changePhase]
  );
  useEffect(() => {
    startListeningRef.current = startListening;
  }, [startListening]);

  const generateReport = useCallback(
    async (msgs) => {
      stopAllAudio();
      changePhase("report_loading");
      try {
        const raw = await callGeminiAPI(buildReportPrompt(msgs), 1200);
        const parsed = extractJson(raw);
        if (!mountedRef.current) return;
        if (parsed && typeof parsed.overallScore === "number") {
          setReport(parsed);
        } else {
          setReport({
            overallScore: null,
            verdict: "Report formatting failed — raw feedback below.",
            rawText: raw,
            categories: [],
            strengths: [],
            improvements: [],
          });
        }
        changePhase("report");
      } catch (e) {
        if (!mountedRef.current) return;
        showBanner("error", "Could not generate the feedback report.", 6000);
        changePhase("report");
        setReport({
          overallScore: null,
          verdict: "Report generation failed. Your transcript is saved above.",
          categories: [],
          strengths: [],
          improvements: [],
        });
      }
    },
    [callGeminiAPI, buildReportPrompt, stopAllAudio, showBanner, changePhase]
  );

  const runInterviewerTurn = useCallback(
    async (msgs) => {
      try {
        const raw = await callGeminiAPI(
          buildTurnPrompt(msgs, questionNumberRef.current),
          600
        );
        if (!mountedRef.current) return;

        const parsed = extractJson(raw);
        const say =
          (parsed?.say && String(parsed.say).trim()) ||
          (raw || "").replace(/[*#`_>]/g, "").trim() ||
          "Sorry, could you repeat that?";
        const qn = Number.isFinite(parsed?.questionNumber)
          ? parsed.questionNumber
          : questionNumberRef.current || 1;
        questionNumberRef.current = qn;
        setQuestionNumber(qn);

        setMessages((prev) => [
          ...prev,
          { role: "interviewer", content: say, timestamp: Date.now() },
        ]);

        if (parsed?.done) {
          changePhase("speaking");
          await speak(say);
          if (!mountedRef.current) return;
          await generateReport([
            ...msgs,
            { role: "interviewer", content: say },
          ]);
        } else {
          await speakThenListen(say);
        }
      } catch (e) {
        if (!mountedRef.current) return;
        console.error("VI turn error:", e);
        showBanner(
          "error",
          "⚠️ The interviewer lost connection. Tap the mic or type to continue.",
          6000
        );
        changePhase("listening");
        setMicMuted(true);
      }
    },
    [
      callGeminiAPI,
      buildTurnPrompt,
      speak,
      speakThenListen,
      generateReport,
      showBanner,
      changePhase,
    ]
  );
  useEffect(() => {
    runInterviewerTurnRef.current = runInterviewerTurn;
  }, [runInterviewerTurn]);

  // ===== Session controls =====
  const startInterview = useCallback(async () => {
    if (!role.trim()) return;
    setMessages([]);
    setReport(null);
    setElapsed(0);
    setQuestionNumber(0);
    questionNumberRef.current = 0;
    submittingRef.current = false;
    setBanner(null);
    changePhase("starting");

    // Ask for mic permission up-front so the first turn flows seamlessly.
    if (SpeechRecognitionCtor && !mutedRef.current && navigator.mediaDevices) {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({
          audio: true,
        });
        stream.getTracks().forEach((t) => t.stop());
        setMicDenied(false);
      } catch (e) {
        setMicDenied(true);
        setMicMuted(true);
        showBanner(
          "info",
          "🎙️ No microphone access — running in type-to-answer mode. The interviewer will still speak.",
          6000
        );
      }
    }

    // iOS/Safari require TTS to start inside a user gesture chain; speaking
    // the first turn right after this click satisfies that.
    await runInterviewerTurnRef.current?.([]);
  }, [role, showBanner, changePhase]);

  const endInterviewEarly = useCallback(() => {
    stopAllAudio();
    if (messagesRef.current.some((m) => m.role === "candidate")) {
      generateReport(messagesRef.current);
    } else {
      changePhase("setup");
      setMessages([]);
    }
  }, [stopAllAudio, generateReport, changePhase]);

  const resetToSetup = useCallback(() => {
    stopAllAudio();
    changePhase("setup");
    setMessages([]);
    setReport(null);
    setInterim("");
    setCapturedSoFar("");
    setElapsed(0);
    setQuestionNumber(0);
    questionNumberRef.current = 0;
  }, [stopAllAudio, changePhase]);

  const finishAnswerNow = useCallback(() => {
    const answer = (
      finalTranscriptRef.current +
      " " +
      (lastInterimRef.current || "")
    )
      .replace(/\s+/g, " ")
      .trim();
    if (answer.length >= 2) submitAnswer(answer);
    else showBanner("info", "Say something first, or type your answer.");
  }, [submitAnswer, showBanner]);

  const skipQuestion = useCallback(() => {
    submitAnswer("(skipped)", { skipped: true });
  }, [submitAnswer]);

  const repeatQuestion = useCallback(async () => {
    const lastQ = [...messagesRef.current]
      .reverse()
      .find((m) => m.role === "interviewer");
    if (!lastQ) return;
    stopRecognition();
    clearTimers();
    await speakThenListen(lastQ.content);
  }, [speakThenListen, stopRecognition, clearTimers]);

  const skipSpeech = useCallback(() => {
    // Barge-in: stop TTS and jump straight to the candidate's turn
    if (phaseRef.current !== "speaking") return;
    stopSpeaking();
    clearTimeout(echoGuardTimerRef.current);
    echoGuardTimerRef.current = null;
    if (mutedRef.current || !SpeechRecognitionCtor) changePhase("listening");
    else startListeningRef.current?.();
  }, [stopSpeaking, changePhase]);

  const toggleMute = useCallback(() => {
    if (mutedRef.current) {
      // Unmute → resume voice capture if it's the candidate's turn
      setMicMuted(false);
      mutedRef.current = false;
      if (phaseRef.current === "listening" && !recognitionRef.current) {
        startListeningRef.current?.();
      }
    } else {
      setMicMuted(true);
      mutedRef.current = true;
      stopRecognition();
      clearTimeout(silenceTimerRef.current);
      silenceTimerRef.current = null;
      setInterim("");
    }
  }, [stopRecognition]);

  const sendTypedAnswer = useCallback(() => {
    const text = textDraft.trim();
    if (!text || phaseRef.current !== "listening") return;
    setTextDraft("");
    submitAnswer(text);
  }, [textDraft, submitAnswer]);

  // ===== Render helpers =====
  const statusLabel = {
    starting: "Connecting you with Alex…",
    speaking: "🔊 Alex is speaking — listen",
    listening: micMuted
      ? "⌨️ Your turn — type your answer"
      : "🎙️ Your turn — speak your answer",
    thinking: "🤔 Alex is thinking…",
    report_loading: "📋 Preparing your feedback report…",
  }[phase];

  // ============================== RENDER ==============================

  if (phase === "setup") {
    return (
      <div className="vi-root">
        <div className="vi-setup">
          {!SpeechRecognitionCtor && (
            <div className="vi-banner info">
              🎙️ Voice input isn't supported in this browser (try Chrome or
              Edge) — you'll type answers while the interviewer speaks.
            </div>
          )}
          <h3 className="vi-setup-title">Who are you interviewing as today?</h3>
          <div className="vi-role-grid">
            {ROLE_PRESETS.map((r) => (
              <button
                key={r.id}
                className={`vi-role-card ${role === r.label ? "selected" : ""}`}
                onClick={() => setRole(r.label)}
              >
                <span className="vi-role-icon">{r.icon}</span>
                <span>{r.label}</span>
              </button>
            ))}
            <div className="vi-role-card vi-role-custom">
              <span className="vi-role-icon">✨</span>
              <input
                type="text"
                value={ROLE_PRESETS.some((r) => r.label === role) ? "" : role}
                onChange={(e) => setRole(e.target.value)}
                placeholder="Custom role, e.g. Senior React Dev @ Google"
              />
            </div>
          </div>

          <div className="vi-setup-row">
            <div className="vi-setup-group">
              <label>Interview style</label>
              <div className="vi-pills">
                {INTERVIEW_TYPES.map((t) => (
                  <button
                    key={t.id}
                    className={`vi-pill ${
                      interviewType === t.id ? "selected" : ""
                    }`}
                    onClick={() => setInterviewType(t.id)}
                    title={t.desc}
                  >
                    {t.label}
                  </button>
                ))}
              </div>
            </div>
            <div className="vi-setup-group">
              <label>Questions</label>
              <div className="vi-pills">
                {[3, 5, 7].map((n) => (
                  <button
                    key={n}
                    className={`vi-pill ${
                      numQuestions === n ? "selected" : ""
                    }`}
                    onClick={() => setNumQuestions(n)}
                  >
                    {n}
                  </button>
                ))}
              </div>
            </div>
            {TTS_SUPPORTED && (
              <div className="vi-setup-group">
                <label>Interviewer voice</label>
                <div className="vi-pills">
                  <button
                    className={`vi-pill ${voiceEnabled ? "selected" : ""}`}
                    onClick={() => setVoiceEnabled(true)}
                  >
                    🔊 On
                  </button>
                  <button
                    className={`vi-pill ${!voiceEnabled ? "selected" : ""}`}
                    onClick={() => setVoiceEnabled(false)}
                  >
                    🔇 Off
                  </button>
                </div>
              </div>
            )}
          </div>

          <button
            className="vi-start-btn"
            disabled={!role.trim()}
            onClick={startInterview}
          >
            🎤 Start Live Interview
          </button>
          <p className="vi-setup-hint">
            Alex speaks each question out loud, listens while you answer, and
            hands you a scored feedback report at the end.
            {SpeechRecognitionCtor
              ? " Just talk — pausing for a couple of seconds sends your answer."
              : ""}
          </p>
        </div>
      </div>
    );
  }

  if (phase === "report_loading" || phase === "report") {
    return (
      <div className="vi-root">
        <div className="vi-report">
          {phase === "report_loading" ? (
            <div className="vi-report-loading">
              <div className="vi-orb thinking" aria-hidden="true">
                <div className="vi-orb-core" />
              </div>
              <p>Scoring your interview…</p>
            </div>
          ) : (
            <>
              <div className="vi-report-header">
                <h3>📋 Interview Feedback — {role}</h3>
                <span className="vi-report-meta">
                  {messages.filter((m) => m.role === "candidate").length}{" "}
                  answers · {formatClock(elapsed)}
                </span>
              </div>

              {report?.overallScore != null && (
                <div className="vi-score-row">
                  <div
                    className="vi-score-ring"
                    style={{
                      "--vi-score": `${Math.max(
                        0,
                        Math.min(100, report.overallScore)
                      )}`,
                    }}
                  >
                    <span className="vi-score-num">{report.overallScore}</span>
                    <span className="vi-score-label">/100</span>
                  </div>
                  <p className="vi-verdict">"{report.verdict}"</p>
                </div>
              )}
              {report?.overallScore == null && report?.verdict && (
                <p className="vi-verdict">{report.verdict}</p>
              )}
              {report?.rawText && (
                <pre className="vi-raw-feedback">{report.rawText}</pre>
              )}

              {report?.categories?.length > 0 && (
                <div className="vi-categories">
                  {report.categories.map((c, i) => (
                    <div key={i} className="vi-category">
                      <div className="vi-category-top">
                        <span>{c.name}</span>
                        <span className="vi-category-score">{c.score}/10</span>
                      </div>
                      <div className="vi-bar">
                        <div
                          className="vi-bar-fill"
                          style={{
                            width: `${
                              Math.max(0, Math.min(10, c.score)) * 10
                            }%`,
                          }}
                        />
                      </div>
                      <p className="vi-category-comment">{c.comment}</p>
                    </div>
                  ))}
                </div>
              )}

              <div className="vi-report-cols">
                {report?.strengths?.length > 0 && (
                  <div className="vi-report-col">
                    <h4>💪 Strengths</h4>
                    <ul>
                      {report.strengths.map((s, i) => (
                        <li key={i}>{s}</li>
                      ))}
                    </ul>
                  </div>
                )}
                {report?.improvements?.length > 0 && (
                  <div className="vi-report-col">
                    <h4>🎯 Work on</h4>
                    <ul>
                      {report.improvements.map((s, i) => (
                        <li key={i}>{s}</li>
                      ))}
                    </ul>
                  </div>
                )}
              </div>

              {report?.sampleAnswerTip && (
                <div className="vi-sample-tip">
                  <h4>✍️ How a stronger answer sounds</h4>
                  <p>{report.sampleAnswerTip}</p>
                </div>
              )}

              <div className="vi-report-actions">
                <button className="vi-primary-btn" onClick={startInterview}>
                  🔁 Practice again
                </button>
                <button className="vi-ghost-btn" onClick={resetToSetup}>
                  ✨ New role
                </button>
              </div>
            </>
          )}
        </div>
      </div>
    );
  }

  // ===== Live session =====
  return (
    <div className="vi-root">
      <div className="vi-session">
        <div className="vi-session-header">
          <span className="vi-role-badge">💼 {role}</span>
          <span className="vi-progress">
            Q{Math.max(1, questionNumber)}/{numQuestions} · ⏱{" "}
            {formatClock(elapsed)}
          </span>
          <button className="vi-end-btn" onClick={endInterviewEarly}>
            ⏹ End &amp; get feedback
          </button>
        </div>

        {banner && (
          <div className={`vi-banner ${banner.kind}`}>{banner.text}</div>
        )}

        <div className="vi-stage">
          <button
            className={`vi-orb ${phase}`}
            onClick={phase === "speaking" ? skipSpeech : undefined}
            title={phase === "speaking" ? "Tap to skip to your turn" : ""}
            aria-label={statusLabel}
          >
            <div className="vi-orb-core">
              {phase === "speaking" && "🗣️"}
              {phase === "listening" && (micMuted ? "⌨️" : "🎙️")}
              {(phase === "thinking" || phase === "starting") && "🧠"}
            </div>
            {phase === "listening" && !micMuted && (
              <div className="vi-eq">
                <span />
                <span />
                <span />
                <span />
                <span />
              </div>
            )}
          </button>
          <p className="vi-status">{statusLabel}</p>

          {phase === "listening" && !micMuted && (capturedSoFar || interim) && (
            <div className="vi-captions">
              {capturedSoFar && <span>{capturedSoFar} </span>}
              {interim && <em>{interim}</em>}
            </div>
          )}
        </div>

        <div className="vi-controls">
          {phase === "speaking" && (
            <button className="vi-ctl" onClick={skipSpeech}>
              ⏭ Skip to my turn
            </button>
          )}
          {phase === "listening" && (
            <>
              {SpeechRecognitionCtor && !micDenied && (
                <button className="vi-ctl" onClick={toggleMute}>
                  {micMuted ? "🎙️ Unmute mic" : "🔇 Mute mic"}
                </button>
              )}
              {!micMuted && (
                <button
                  className="vi-ctl vi-ctl-primary"
                  onClick={finishAnswerNow}
                >
                  ✅ Done answering
                </button>
              )}
              <button className="vi-ctl" onClick={repeatQuestion}>
                🔁 Repeat question
              </button>
              <button className="vi-ctl" onClick={skipQuestion}>
                ⏭ Skip question
              </button>
            </>
          )}
        </div>

        {phase === "listening" && (micMuted || !SpeechRecognitionCtor) && (
          <div className="vi-text-input">
            <textarea
              value={textDraft}
              onChange={(e) => setTextDraft(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === "Enter" && !e.shiftKey) {
                  e.preventDefault();
                  sendTypedAnswer();
                }
              }}
              placeholder="Type your answer… (Enter to send)"
              rows={3}
              autoFocus
            />
            <button
              onClick={sendTypedAnswer}
              disabled={!textDraft.trim()}
              className="vi-send-btn"
            >
              Send →
            </button>
          </div>
        )}

        <div className="vi-transcript">
          {messages.map((msg, i) => (
            <div key={i} className={`vi-msg ${msg.role}`}>
              <div className="vi-msg-avatar">
                {msg.role === "interviewer" ? "👔" : "👤"}
              </div>
              <div className="vi-msg-bubble">
                <span className="vi-msg-role">
                  {msg.role === "interviewer" ? "Alex · Interviewer" : "You"}
                </span>
                <p>{msg.content}</p>
              </div>
            </div>
          ))}
          {phase === "thinking" && (
            <div className="vi-msg interviewer">
              <div className="vi-msg-avatar">👔</div>
              <div className="vi-msg-bubble vi-typing">
                <span />
                <span />
                <span />
              </div>
            </div>
          )}
          <div ref={transcriptEndRef} />
        </div>
      </div>
    </div>
  );
}
